import React, { useEffect, useState, useContext } from "react";
import { useParams } from "react-router-dom";
import { productAPI } from "../api";
import { CartContext } from "../context/CartContext";

const ProductDetail = () => {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const { addToCart } = useContext(CartContext);

  useEffect(() => {
    let mounted = true;
    productAPI.getProductById(id).then(res => { if (mounted) setProduct(res.data); }).catch(err => console.error(err));
    return () => mounted = false;
  }, [id]);

  if (!product) return <div style={{ padding: 20 }}>Đang tải chi tiết...</div>;

  return (
    <div style={{ padding: "32px 10%", display: "flex", gap: 28 }}>
      <div style={{ flex: 1 }}>
        <img src={product.image || product.images?.[0] || "/placeholder.png"} alt={product.name} style={{ width: "100%", maxHeight: 520, objectFit: "cover", borderRadius: 12 }} />
      </div>
      <div style={{ width: 420 }}>
        <h2 style={{ fontSize: 28 }}>{product.name}</h2>
        <div style={{ color: "#8b5e3c", fontWeight: 700, fontSize: 20 }}>{(product.price || 0).toLocaleString()}₫</div>
        <p style={{ marginTop: 12 }}>{product.description}</p>
        <div style={{ marginTop: 20 }}>
          <button className="btn" onClick={() => addToCart(product, 1)}>Thêm vào giỏ</button>
        </div>
      </div>
    </div>
  );
};

export default ProductDetail;
